changeSet.sql:
UPDATE profil_metier SET description = 'Creation des boutiques, gestion des acces, redevances, reporting et supervision ADM' WHERE code = 'MANAGER_ADM';
DELETE FROM rel_profil_metier__permissions relation USING profil_metier profil, permission_metier permission WHERE relation.profil_metier_id = profil.id AND relation.permissions_id = permission.id AND profil.code = 'MANAGER_ADM' AND permission.code IN ('SALES_MANAGE', 'STOCK_READ', 'STOCK_MANAGE');
INSERT INTO rel_profil_metier__permissions (profil_metier_id, permissions_id) SELECT profil.id, permission.id FROM profil_metier profil JOIN permission_metier permission ON permission.code IN ( 'USER_READ', 'USER_CREATE', 'USER_UPDATE', 'USER_DEACTIVATE', 'USER_MANAGE', 'SALES_READ', 'REPORTING_READ', 'REPORTING_EXPORT', 'ROYALTY_READ', 'ROYALTY_MANAGE', 'SETTINGS_READ', 'SETTINGS_MANAGE', 'AUDIT_READ' ) WHERE profil.code = 'MANAGER_ADM' ON CONFLICT DO NOTHING;
